-- Comprehensive U.S. institution directory and verified pending-domain intake.
-- Institution identity comes from NCES IPEDS HD2024. Email eligibility remains
-- a separately reviewed, exact-domain decision.

create type public.institution_directory_status as enum ('active','inactive','closed','merged','renamed','duplicate');
create type public.institution_registration_status as enum ('open','suspended','closed');
create type public.domain_review_confidence as enum ('low','medium','high');

create table public.institution_directory (
  id text primary key check (id ~ '^[a-z0-9_-]+:[a-z0-9_-]+$'),
  source text not null check (source ~ '^[a-z0-9_-]{2,40}$'),
  source_id text not null check (char_length(source_id) between 1 and 80),
  source_year smallint not null check (source_year between 1900 and 2200),
  name text not null check (char_length(name) between 2 and 300),
  aliases text not null default '' check (char_length(aliases) <= 2000),
  city text not null default '' check (char_length(city) <= 160),
  region text not null default '' check (char_length(region) <= 20),
  postal_code text not null default '' check (char_length(postal_code) <= 20),
  country_code text not null default 'US' check (country_code ~ '^[A-Z]{2}$'),
  website text check (website is null or website ~ '^https?://[^[:space:]]+$'),
  status public.institution_directory_status not null,
  registration_status public.institution_registration_status not null default 'closed',
  merged_into_id text references public.institution_directory(id) on delete restrict,
  campus_id uuid references public.campuses(id) on delete restrict,
  sector smallint,
  control smallint,
  level smallint,
  source_url text not null check (source_url ~ '^https://[^[:space:]]+$'),
  source_hash text not null check (source_hash ~ '^[0-9a-f]{64}$'),
  created_at timestamptz not null default now(),
  updated_at timestamptz not null default now(),
  unique (source,source_id),
  check (merged_into_id is null or merged_into_id <> id)
);

create unique index institution_directory_campus_idx on public.institution_directory(campus_id) where campus_id is not null;
create index institution_directory_name_trgm_idx on public.institution_directory using gin (lower(name) extensions.gin_trgm_ops);
create index institution_directory_aliases_trgm_idx on public.institution_directory using gin (lower(aliases) extensions.gin_trgm_ops);
create index institution_directory_region_name_idx on public.institution_directory(region,name);
create index institution_directory_registration_idx on public.institution_directory(registration_status,status);

alter table public.institution_directory enable row level security;
revoke all on table public.institution_directory from public,anon,authenticated;
grant all on table public.institution_directory to service_role;

