alter table public.campus_email_domains
  add column institution_id text references public.institution_directory(id) on delete restrict,
  add column reviewed_by text,
  add column review_confidence public.domain_review_confidence;

alter table public.campus_email_domains
  add constraint campus_email_domains_reviewer_check
    check (reviewed_by is null or char_length(reviewed_by) between 2 and 160) not valid,
  add constraint campus_email_domains_confidence_check
    check (review_confidence is null or review_status in ('reviewed','ambiguous','rejected')) not valid;
alter table public.campus_email_domains validate constraint campus_email_domains_reviewer_check;
alter table public.campus_email_domains validate constraint campus_email_domains_confidence_check;
create index campus_email_domains_institution_idx on public.campus_email_domains(institution_id);

create table public.institution_domain_verification_challenges (
  id uuid primary key default gen_random_uuid(),
  institution_id text not null references public.institution_directory(id) on delete restrict,
  email_domain extensions.citext not null,
  email_hash text not null check (email_hash ~ '^[0-9a-f]{64}$'),
  code_hash text not null check (code_hash ~ '^[0-9a-f]{64}$'),
  requester_hash text not null check (requester_hash ~ '^[0-9a-f]{64}$'),
  expires_at timestamptz not null,
  attempts smallint not null default 0 check (attempts between 0 and 10),
  consumed_at timestamptz,
  created_at timestamptz not null default now(),
  check (lower(email_domain::text)=email_domain::text and email_domain::text ~ '^[a-z0-9](?:[a-z0-9.-]{0,251}[a-z0-9])?$' and position('.' in email_domain::text)>0),
  check (expires_at > created_at)
);
create index institution_domain_challenge_lookup_idx
  on public.institution_domain_verification_challenges(id,email_hash,expires_at)
  where consumed_at is null;
create index institution_domain_challenge_cleanup_idx on public.institution_domain_verification_challenges(expires_at);

create table public.institution_domain_requests (
  id uuid primary key default gen_random_uuid(),
  institution_id text not null references public.institution_directory(id) on delete restrict,
  email_domain extensions.citext not null,
  status public.school_request_status not null default 'pending',
  verified_email_hash text not null check (verified_email_hash ~ '^[0-9a-f]{64}$'),
  verification_count integer not null default 1 check (verification_count between 1 and 1000000),
  first_verified_at timestamptz not null default now(),
  last_verified_at timestamptz not null default now(),
  resolution_campus_id uuid references public.campuses(id) on delete set null,
  reviewed_by text check (reviewed_by is null or char_length(reviewed_by) between 2 and 160),
  review_confidence public.domain_review_confidence,
  evidence_url text check (evidence_url is null or evidence_url ~ '^https://[^[:space:]]+$'),
  reviewed_at timestamptz,
  operator_notes text check (operator_notes is null or char_length(operator_notes) <= 2000),
  unique (institution_id,email_domain),
  check (lower(email_domain::text)=email_domain::text and email_domain::text ~ '^[a-z0-9](?:[a-z0-9.-]{0,251}[a-z0-9])?$' and position('.' in email_domain::text)>0)
);
create index institution_domain_requests_queue_idx on public.institution_domain_requests(status,last_verified_at desc);
create index institution_domain_requests_domain_idx on public.institution_domain_requests(lower(email_domain::text));

alter table public.institution_domain_verification_challenges enable row level security;
alter table public.institution_domain_requests enable row level security;
revoke all on table public.institution_domain_verification_challenges,public.institution_domain_requests from public,anon,authenticated;
grant all on table public.institution_domain_verification_challenges,public.institution_domain_requests to service_role;

create or replace function public.search_institution_directory(search_query text,result_limit integer default 20)
returns table(
  id text,name text,city text,region text,status public.institution_directory_status,
  registration_status public.institution_registration_status,campus_id uuid,availability text
)
language sql stable security definer set search_path = '' as $$
  with input as (
    select lower(trim(coalesce(search_query,''))) as query,greatest(1,least(coalesce(result_limit,20),50)) as take
  )
  select i.id,i.name,i.city,i.region,i.status,i.registration_status,i.campus_id,
    case
      when i.registration_status<>'open' then 'unavailable'
      when c.status='enabled' and exists(
        select 1 from public.campus_email_domains d
        where d.campus_id=i.campus_id and d.is_enabled and d.review_status='reviewed'
          and d.domain_kind in ('student','institutional')
      ) then 'supported'
      when i.registration_status='open' then 'verification_required'
      else 'unavailable'
    end as availability
  from public.institution_directory i
  cross join input
  left join public.campuses c on c.id=i.campus_id
  where input.query='' or lower(i.name) like '%'||input.query||'%'
    or lower(i.aliases) like '%'||input.query||'%'
    or lower(i.city||' '||i.region) like '%'||input.query||'%'
  order by
    case when lower(i.name)=input.query then 0 when lower(i.name) like input.query||'%' then 1 else 2 end,
    i.name,i.region,i.id
  limit (select take from input)
$$;
revoke all on function public.search_institution_directory(text,integer) from public,anon,authenticated;
grant execute on function public.search_institution_directory(text,integer) to service_role;

create or replace function public.complete_institution_domain_verification(
  challenge_id uuid,submitted_email_hash text,submitted_code_hash text
)
returns table(outcome text,request_id uuid,request_status public.school_request_status)
language plpgsql security definer set search_path = '' as $$
declare selected public.institution_domain_verification_challenges;
begin
  select * into selected from public.institution_domain_verification_challenges
  where id=challenge_id for update;
  if selected.id is null or selected.consumed_at is not null or selected.expires_at<=now() or selected.attempts>=5 then
    return query select 'invalid'::text,null::uuid,null::public.school_request_status;
    return;
  end if;
  update public.institution_domain_verification_challenges set attempts=attempts+1 where id=selected.id;
  if selected.email_hash<>submitted_email_hash or selected.code_hash<>submitted_code_hash then
    return query select 'invalid'::text,null::uuid,null::public.school_request_status;
    return;
  end if;
  update public.institution_domain_verification_challenges set consumed_at=now() where id=selected.id;
  return query
    insert into public.institution_domain_requests(institution_id,email_domain,verified_email_hash)
    values(selected.institution_id,selected.email_domain,selected.email_hash)
    on conflict (institution_id,email_domain) do update set
      verification_count=least(public.institution_domain_requests.verification_count+1,1000000),
      last_verified_at=now(),
      verified_email_hash=excluded.verified_email_hash
    returning 'verified'::text,id,status;
end $$;
revoke all on function public.complete_institution_domain_verification(uuid,text,text) from public,anon,authenticated;
grant execute on function public.complete_institution_domain_verification(uuid,text,text) to service_role;

create or replace function public.merge_institution_directory(
  source_institution_id text,target_institution_id text,merge_status public.institution_directory_status,input_reviewer text
)
returns uuid
language plpgsql security definer set search_path = '' as $$
declare source_row public.institution_directory;
declare target_row public.institution_directory;
declare retained_campus uuid;
begin
  if source_institution_id=target_institution_id or merge_status not in ('merged','duplicate')
    or char_length(trim(input_reviewer)) not between 2 and 160 then
    raise exception 'invalid institution merge' using errcode='23514';
  end if;
  perform 1 from public.institution_directory where id in (source_institution_id,target_institution_id) order by id for update;
  select * into source_row from public.institution_directory where id=source_institution_id;
  select * into target_row from public.institution_directory where id=target_institution_id;
  if source_row.id is null or target_row.id is null then raise exception 'institution not found' using errcode='P0002'; end if;
  if source_row.campus_id is not null and target_row.campus_id is not null and source_row.campus_id<>target_row.campus_id then
    raise exception 'institutions link different campuses' using errcode='23505';
  end if;
  retained_campus:=coalesce(target_row.campus_id,source_row.campus_id);
  update public.institution_directory set campus_id=null,status=merge_status,registration_status='closed',
    merged_into_id=target_row.id,updated_at=now() where id=source_row.id;
  if target_row.campus_id is null and source_row.campus_id is not null then
    update public.institution_directory set campus_id=source_row.campus_id,updated_at=now() where id=target_row.id;
  end if;
  update public.campus_email_domains set institution_id=target_row.id where institution_id=source_row.id;
  update public.institution_domain_verification_challenges set institution_id=target_row.id where institution_id=source_row.id;
  update public.institution_domain_requests source_request set institution_id=target_row.id
    where source_request.institution_id=source_row.id
      and not exists(
        select 1 from public.institution_domain_requests target_request
        where target_request.institution_id=target_row.id
          and target_request.email_domain=source_request.email_domain
      );
  update public.institution_domain_requests set
      status='duplicate',
      reviewed_by=coalesce(reviewed_by,trim(input_reviewer)),
      reviewed_at=coalesce(reviewed_at,now()),
      operator_notes=coalesce(operator_notes,'Institution record merged into '||target_row.id)
    where institution_id=source_row.id;
  insert into public.directory_operator_audit(campus_id,action,target_type,target_id,metadata)
    values(retained_campus,'institution.operator_'||merge_status::text,'institution_directory',source_row.id,
      jsonb_build_object('into',target_row.id,'reviewer',trim(input_reviewer)));
  return retained_campus;
end $$;
revoke all on function public.merge_institution_directory(text,text,public.institution_directory_status,text) from public,anon,authenticated;
grant execute on function public.merge_institution_directory(text,text,public.institution_directory_status,text) to service_role;

create or replace function public.approve_institution_domain_request(
  request_id uuid,target_campus_id uuid,mapping_kind public.campus_domain_kind,input_evidence_url text,
  input_reviewer text,input_confidence public.domain_review_confidence,enable_mapping boolean default false,input_notes text default null
)
returns table(out_institution_id text,out_campus_id uuid,out_email_domain text,out_mapping_enabled boolean)
language plpgsql security definer set search_path = '' as $$
declare selected public.institution_domain_requests;
declare institution public.institution_directory;
declare domain_collision boolean;
begin
  if mapping_kind not in ('student','institutional') or input_evidence_url !~ '^https://[^[:space:]]+$'
    or char_length(trim(input_reviewer)) not between 2 and 160 or input_confidence is null then
    raise exception 'approval evidence is incomplete' using errcode='23514';
  end if;
  select * into selected from public.institution_domain_requests where id=request_id for update;
  if selected.id is null then raise exception 'domain request not found' using errcode='P0002'; end if;
  select * into institution from public.institution_directory where id=selected.institution_id for update;
  if institution.id is null then raise exception 'institution not found' using errcode='P0002'; end if;
  if not exists(select 1 from public.campuses where id=target_campus_id) then raise exception 'campus not found' using errcode='P0002'; end if;
  if institution.campus_id is not null and institution.campus_id<>target_campus_id then
    raise exception 'institution is linked to another campus' using errcode='23505';
  end if;
  select exists(
    select 1 from public.campus_email_domains d
    where lower(d.domain::text)=lower(selected.email_domain::text) and d.is_enabled and d.campus_id<>target_campus_id
  ) into domain_collision;
  if enable_mapping and domain_collision then raise exception 'domain is enabled for another campus' using errcode='23505'; end if;

  update public.institution_directory set campus_id=target_campus_id,updated_at=now() where id=institution.id and campus_id is null;
  insert into public.campus_email_domains(
    campus_id,domain,is_enabled,review_status,domain_kind,source_url,source_label,reviewed_at,review_notes,institution_id,reviewed_by,review_confidence
  ) values(
    target_campus_id,selected.email_domain,enable_mapping,'reviewed',mapping_kind,input_evidence_url,
    'Operator-reviewed verified domain request',now(),input_notes,institution.id,trim(input_reviewer),input_confidence
  )
  on conflict (campus_id,domain) do update set
    is_enabled=excluded.is_enabled,review_status='reviewed',domain_kind=excluded.domain_kind,source_url=excluded.source_url,
    source_label=excluded.source_label,reviewed_at=excluded.reviewed_at,review_notes=excluded.review_notes,
    institution_id=excluded.institution_id,reviewed_by=excluded.reviewed_by,review_confidence=excluded.review_confidence;
  update public.institution_domain_requests set status='approved',resolution_campus_id=target_campus_id,
    reviewed_by=trim(input_reviewer),review_confidence=input_confidence,evidence_url=input_evidence_url,
    reviewed_at=now(),operator_notes=input_notes where id=selected.id;
  insert into public.directory_operator_audit(campus_id,action,target_type,target_id,metadata)
    values(target_campus_id,'institution_domain_request.operator_approved','institution_domain_request',selected.id::text,
      jsonb_build_object('institutionId',institution.id,'domain',selected.email_domain::text,'enabled',enable_mapping,'confidence',input_confidence));
  return query select institution.id,target_campus_id,selected.email_domain::text,enable_mapping;
end $$;
revoke all on function public.approve_institution_domain_request(uuid,uuid,public.campus_domain_kind,text,text,public.domain_review_confidence,boolean,text) from public,anon,authenticated;
grant execute on function public.approve_institution_domain_request(uuid,uuid,public.campus_domain_kind,text,text,public.domain_review_confidence,boolean,text) to service_role;

-- Connect existing reviewed and intentionally ambiguous campuses to their
-- authoritative institution records. This never changes domain eligibility.
with links(slug,institution_id) as (values
  ('michigan-state-university','ipeds:171100'),
  ('university-of-illinois-urbana-champaign','ipeds:145637'),
  ('university-of-wisconsin-madison','ipeds:240444'),
  ('university-of-chicago','ipeds:144050'),
  ('northwestern-university','ipeds:147767'),
  ('university-of-notre-dame','ipeds:152080'),
  ('stanford-university','ipeds:243744'),
  ('university-of-california-berkeley','ipeds:110635'),
  ('yale-university','ipeds:130794'),
  ('princeton-university','ipeds:186131'),
  ('duke-university','ipeds:198419'),
  ('vanderbilt-university','ipeds:221999'),
  ('rice-university','ipeds:227757'),
  ('georgia-institute-of-technology','ipeds:139755'),
  ('university-of-texas-at-austin','ipeds:228778'),
  ('texas-a-and-m-university','ipeds:228723'),
  ('dartmouth-college','ipeds:182670'),
  ('university-of-michigan-ann-arbor','ipeds:170976'),
  ('university-of-michigan-dearborn','ipeds:171137'),
  ('purdue-university-west-lafayette','ipeds:243780'),
  ('purdue-university-indianapolis','ipeds:500139')
)
update public.institution_directory i set campus_id=c.id,updated_at=now()
from links l join public.campuses c on c.slug=l.slug
where i.id=l.institution_id;

update public.institution_directory
set registration_status='open',updated_at=now()
where id in ('ipeds:170976','ipeds:171137','ipeds:243780','ipeds:500139');

update public.campus_email_domains d set institution_id=i.id
from public.institution_directory i where i.campus_id=d.campus_id;

update public.campus_email_domains
set review_confidence=case when review_status='reviewed' and domain_kind in ('student','institutional') then 'high'::public.domain_review_confidence else 'medium'::public.domain_review_confidence end,
    reviewed_by=coalesce(reviewed_by,'Bundled directory review v1')
where review_status in ('reviewed','ambiguous');

do $$
begin
  if (select count(*) from public.institution_directory)<>6072 then raise exception 'IPEDS HD2024 directory count mismatch'; end if;
  if (select count(*) from public.institution_directory where source='ipeds' and source_year=2024)<>6072 then raise exception 'IPEDS provenance mismatch'; end if;
  if (select count(*) from public.search_institution_directory('',50))<>50 then raise exception 'institution search is unavailable'; end if;
  if (select availability from public.search_institution_directory('Michigan State University',10) where id='ipeds:171100')<>'supported' then raise exception 'MSU directory link is not supported'; end if;
  if (select availability from public.search_institution_directory('Purdue University - Indianapolis',10) where id='ipeds:500139')<>'verification_required' then raise exception 'ambiguous Purdue campus must route to review'; end if;
  if exists(select 1 from public.institution_directory where campus_id is not null group by campus_id having count(*)>1) then raise exception 'duplicate campus-directory links'; end if;
  if exists(select 1 from pg_class c join pg_namespace n on n.oid=c.relnamespace where n.nspname='public' and c.relname in ('institution_directory','institution_domain_verification_challenges','institution_domain_requests') and not c.relrowsecurity) then raise exception 'institution tables must retain RLS'; end if;
end $$;
